from adk import Context
from collections import deque

def detect_circular_delegation(ctx: Context) -> dict:
    if not hasattr(ctx, '_delegation_trace'):
        ctx._delegation_trace = deque(maxlen=10)

    current_agent = ctx.current_agent_id
    ctx._delegation_trace.append(current_agent)

    # Check for cycles
    if len(ctx._delegation_trace) > 3:
        recent = list(ctx._delegation_trace)[-4:]
        if recent[0] == recent[-1]:
            return {
                'issue': 'CIRCULAR_DELEGATION',
                'cycle': list(recent),
                'size': len(ctx.state)
            }
    return {'issue': 'OK'}

import json
from adk import Context

def detect_memory_corruption(ctx: Context) -> dict:
    if not hasattr(ctx, '_memory_baseline'):
        ctx._memory_baseline = len(str(ctx.user_memory))

    current_size = len(str(ctx.user_memory))

    # Detect truncation (size decreased during streaming)
    if current_size < ctx._memory_baseline * 0.8:
        return {
            'issue': 'MEMORY_TRUNCATION',
            'before': ctx._memory_baseline,
            'after': current_size,
            'loss_pct': (1 - current_size/ctx._memory_baseline)*100
        }

    ctx._memory_baseline = current_size
    return {'issue': 'OK'}

from adk import Context, ToolResponse
import json

def detect_tool_mismatch(ctx: Context, tool_response: ToolResponse) -> dict:
    expected_format = ctx.get('tools_schema', {}).get(ctx.current_agent_id, 'json')

    try:
        response_data = tool_response.content
        json.loads(response_data)  # Try JSON parse

        if expected_format != 'json':
            return {
                'issue': 'FORMAT_MISMATCH',
                'expected': expected_format,
                'actual': 'json',
                'agent': ctx.current_agent_id
            }
    except json.JSONDecodeError:
        if expected_format == 'json':
            return {
                'issue': 'FORMAT_MISMATCH',
                'expected': 'json',
                'actual': 'invalid',
                'agent': ctx.current_agent_id
            }

    return {'issue': 'OK'}

