from adk import Context

class StreamingBuffer:
    def __init__(self):
        self.chunks = []

    def append(self, chunk: str):
        self.chunks.append(chunk)

    def commit(self, ctx: Context):
        full_content = ''.join(self.chunks)
        # Append, don't overwrite
        if ctx.user_memory:
            ctx.user_memory += '\n' + full_content
        else:
            ctx.user_memory = full_content

        self.chunks.clear()

